#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;

typedef struct BinarySearchTree {
    Node* root;
} BinarySearchTree;

Node* createNode(int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->left = NULL;
    node->right = NULL;
    return node;
}

void initBST(BinarySearchTree* bst) {
    bst->root = NULL;
}

void insert(BinarySearchTree* bst, int value) {
    if (!bst->root) {
        bst->root = createNode(value);
    } else {
        insertRecursive(bst->root, value);
    }
}

void insertRecursive(Node* node, int value) {
    if (value < node->value) {
        if (!node->left) {
            node->left = createNode(value);
        } else {
            insertRecursive(node->left, value);
        }
    } else {
        if (!node->right) {
            node->right = createNode(value);
        } else {
            insertRecursive(node->right, value);
        }
    }
}

int search(Node* node, int value) {
    if (!node || node->value == value) {
        return node != NULL;
    }
    if (value < node->value) {
        return search(node->left, value);
    }
    return search(node->right, value);
}

Node* findMin(Node* node) {
    Node* current = node;
    while (current->left) {
        current = current->left;
    }
    return current;
}

Node* deleteRecursive(Node* node, int value) {
    if (!node) return node;
    if (value < node->value) {
        node->left = deleteRecursive(node->left, value);
    } else if (value > node->value) {
        node->right = deleteRecursive(node->right, value);
    } else {
        if (!node->left) {
            Node* temp = node->right;
            free(node);
            return temp;
        }
        if (!node->right) {
            Node* temp = node->left;
            free(node);
            return temp;
        }
        Node* minNode = findMin(node->right);
        node->value = minNode->value;
        node->right = deleteRecursive(node->right, minNode->value);
    }
    return node;
}

void delete(BinarySearchTree* bst, int value) {
    bst->root = deleteRecursive(bst->root, value);
}

void inorder(Node* node, int* arr, int* index) {
    if (node) {
        inorder(node->left, arr, index);
        arr[(*index)++] = node->value;
        inorder(node->right, arr, index);
    }
}

void printArray(int* arr, int size) {
    printf("[");
    for (int i = 0; i < size; i++) {
        printf("%d", arr[i]);
        if (i < size - 1) printf(", ");
    }
    printf("]\n");
}

int main() {
    BinarySearchTree bst;
    initBST(&bst);
    int values[] = {10, 5, 15};
    for (int i = 0; i < 3; i++) {
        insert(&bst, values[i]);
    }
    int result[10], index = 0;
    inorder(bst.root, result, &index);
    printf("BST after insert: ");
    printArray(result, index);
    printf("Search 5: %d\n", search(bst.root, 5));
    delete(&bst, 15);
    index = 0;
