    static void Main() {
        BinarySearchTree bst = new BinarySearchTree();
        int[] values = { 10, 5, 15 };
        foreach (var val in values) {
            bst.Insert(val);
        }
        Console.WriteLine("BST after insert: [" + string.Join(", ", bst.ToList()) + "]");
